   257→  /**
   258→   * Creates a URL prefix bound to chunked handler. Handler is expected to
   259→   * supply a method makeRequest(AdminStream&).
   260→   *
   261→   * @param prefix the prefix to register
   262→   * @param help_text a help text ot display in a table in the admin home page
   263→   * @param handler the Handler object for the admin subsystem, supplying makeContext().
   264→   * @param removeable indicates whether the handler can be removed after being added
   265→   * @param mutates_state indicates whether the handler will mutate state and therefore
   266→   *                      must be accessed via HTTP POST rather than GET.
   267→   * @return the UrlHandler.
   268→   */
   269→  template <class Handler>
   270→  UrlHandler makeStreamingHandler(const std::string& prefix, const std::string& help_text,
   271→                                  Handler& handler, bool removable, bool mutates_state) {
   272→    return {prefix, help_text,
   273→            [&handler](AdminStream& admin_stream) -> Admin::RequestPtr {
   274→              return handler.makeRequest(admin_stream);
   275→            },
   276→            removable, mutates_state};
   277→  }
